import React, { useEffect, useState, useRef } from 'react';

interface Log {
    id: string;
    msg: string;
    timestamp: string;
}

export const SystemTerminal: React.FC<{ logs?: Log[] }> = ({ logs = [] }) => {
    const [displayLogs, setDisplayLogs] = useState<string[]>([]);
    const scrollRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (logs.length > 0) {
            const latest = logs[logs.length - 1];
            setDisplayLogs(prev => [...prev, `>> [${latest.timestamp}] ${latest.msg}`].slice(-50));
        } else if (displayLogs.length === 0) {
            setDisplayLogs([
                '>> [SYSTEM] INITIALIZING CORE ORCHESTRATOR...',
                '>> [SYSTEM] WEBSOCKET CONNECTED: WS://LOCALHOST:8000/WS',
                '>> [SYSTEM] AGENT_REGISTRY SYNCED (4 NODES ACTIVE)',
                '>> [SYSTEM] TELEMETRY STREAM: AUTHENTICATED',
            ]);
        }
    }, [logs]);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [displayLogs]);

    return (
        <div className="flex flex-col h-full">
            <div className="flex justify-between items-center mb-4 px-2">
                <div className="flex items-center space-x-2">
                    <div className="w-1.5 h-1.5 bg-white rounded-full animate-pulse" />
                    <span className="nothing-text-label">SYSTEM_TERMINAL</span>
                </div>
                <div className="flex space-x-4">
                    <span className="text-[8px] text-white/30 font-mono tracking-widest">ENCRYPTION: AES-256</span>
                    <span className="text-[8px] text-white/30 font-mono tracking-widest">UPTIME: 99.98%</span>
                </div>
            </div>

            <div
                ref={scrollRef}
                className="flex-grow overflow-y-auto scrollbar-hide font-mono text-[10px] space-y-1 opacity-70 mask-linear-fade"
            >
                {displayLogs.map((log, i) => (
                    <div key={i} className="flex space-x-2 terminal-text hover:text-white transition-colors">
                        <span className="text-white/20 select-none">{i.toString().padStart(3, '0')}</span>
                        <span>{log}</span>
                    </div>
                ))}
                <div className="flex items-center space-x-1 terminal-text">
                    <span className="text-white/20 select-none">{(displayLogs.length).toString().padStart(3, '0')}</span>
                    <span>&gt;&gt;</span>
                    <span className="w-2 h-3 bg-white/40 animate-pulse" />
                </div>
            </div>
        </div>
    );
};
